const test = require("node:test");
const assert = require("node:assert");
const { total } = require("../src/cart.js");

test("exactly 100 gets no discount", () => {
  assert.strictEqual(total([{ price: 100, qty: 1 }]), 100);
  assert.strictEqual(total([{ price: 25, qty: 4 }]), 100);
});
